class Solution {
    public long smallestNumber(long num) {
        int[] digits = new int[10];
        int count = 0;
        while (num != 0) {
            digits[count++] = (int) (num % 10);
            num /= 10;
        }
        Arrays.sort(digits);
        long result = 1;
        for (int digit : digits) {
            result *= 10;
            result += digit;
        }
        return result;
    }
}
```

